%[text] # MATLAB's Solvers
clear all
f = @(t, x)  -(6 / 5 + sin(10 * t)) * x;
%Using Runge-Kutta (2,3) (which we will explain in time) to solve nonstiff
%ODEs
%Syntax: function, timespan, initial value (preset accuracy tolerance)
[t1 f1] = ode23(f, [0 5], 1) %[output:91d1fa01] %[output:5b88fdb6]
tiledlayout(2,1) %[output:004cd626]
nexttile %[output:004cd626]
p = plot(t1, f1); %[output:004cd626]
p(1).LineWidth = 3; %[output:004cd626]
set(gca,'fontsize', 16)  %[output:004cd626]

nexttile %[output:004cd626]
exact = @(t) exp(- 1/ 10 - (6 * t) / 5 + 1 / 10 * cos(10 * t));
p = plot(t1, abs(exact(t1) - f1)); %[output:004cd626]
p(1).LineWidth = 3; %[output:004cd626]
set(gca,'fontsize', 16) %[output:004cd626]


%[text] # Our accuracy here isn't great (10^-4)...
%%
%[text] # So we try to force accuracy by changing settings
opts = odeset('Stats','on', 'RelTol',1e-6);

[t2 f2] = ode23(f, [0 5], 1, opts); %[output:0fa333f9]
%%

%Notice the difference in the number of steps

length(t1) %[output:2992d1ba]
length(t2) %[output:89793700]
%%
%[text] # Did We Get the Accuracy We Wanted?
figure %[output:712b048e]
p = plot(t2, abs(exact(t2) - f2)); %[output:712b048e]
p(1).LineWidth = 3; %[output:712b048e]
set(gca,'fontsize', 16) %[output:712b048e]

%Certainly better than before, but still some odd behavior. 
%%
%[text] # Let t Get Large?
[t3 f3] = ode23(f, [0 50], 1, opts); %[output:1c8ea73a]
p = plot(t3, abs(exact(t3) - f3)); %[output:9fd191a6]
p(1).LineWidth = 3; %[output:9fd191a6]
set(gca,'fontsize', 16) %[output:9fd191a6]
%%
%[text] # We Have Other Solvers ?
%Runge-Kutta (4,5)-- higher order Taylor approx should mean better accuracy

[t4 f4] = ode45(f, [0 50], 1, opts); %[output:9f04dea0]
p = plot(t4, abs(exact(t4) - f4)); %[output:5b64a76a]
p(1).LineWidth = 3; %[output:5b64a76a]
set(gca,'fontsize', 16) %[output:5b64a76a]
%But we aren't seeing that. 
%%
%[text] # Even Solvers More Solvers
[t5 f5] = ode89(f, [0 50], 1, opts); %[output:42ee6f63] %[output:4bb155ba]
p = plot(t5, abs(exact(t5) - f5)); %[output:76b1b67c]
p(1).LineWidth = 3; %[output:76b1b67c]
set(gca,'fontsize', 16) %[output:76b1b67c]
%Catastrophic issues in this case for this example...
%Even using stiff methods doesn't help

%[output:3eb8aaec] %[output:9bf5ff0b] %[output:5fbbfab5]

%%
%[text] # Coding Example: Euler's method
%[text] 
function [T,X] = euler(f, x0, t0, t, nsteps)
%Euler's method from time t0 to t, with x(t0) = x0
%f is an anonymous function of t and x

T = linspace(t0,t,nsteps+1);
h = abs(t-t0)/(nsteps);
X = zeros(1,nsteps+1);
X(1) = x0;

for j =2:nsteps+1
X(j) = X(j-1) + h*f(T(j-1),X(j-1));
end
end
%%
